USE techmart;

-- ---- Users -----------------------------------------------------------

-- ---- Categories ------------------------------------------------------

-- ---- Warehouses ------------------------------------------------------

-- ---- Products (20) ---------------------------------------------------

-- ---- Inventory (every product in every warehouse; product 20 is OUT OF STOCK to demo back-in-stock) ----
SELECT p.id, w.id,
       CASE WHEN p.id = 20 THEN 0
            WHEN p.id IN (9, 13) THEN 5            -- intentionally low stock to show alerts
            ELSE 20 + (p.id * 2) + (w.id * 4)
       END,
       0, 10, 50, NOW()
FROM products p CROSS JOIN warehouses w;

-- ---- Sample order 1: DELIVERED + COMPLETED payment ------------------
SELECT 'TM-SAMPLE-0001', u.id, 'DELIVERED', 369990.00, 29599.20, 350.00, 399939.20,
       '123 Galle Road, Colombo 03', NOW() - INTERVAL 5 DAY, NOW() - INTERVAL 5 DAY, NOW() - INTERVAL 4 DAY, NOW() - INTERVAL 2 DAY
FROM users u WHERE u.username = 'customer';

SELECT o.id, p.id, 1, 369990.00, 369990.00, p.name, p.sku
FROM orders o JOIN products p ON p.sku = 'SM-SGS24U'
WHERE o.order_number = 'TM-SAMPLE-0001';

SELECT o.id, 'PAY-SAMPLE-0001', 'PH-SAMPLE-1', 'COMPLETED', 399939.20, 'LKR', 'VISA', NOW() - INTERVAL 5 DAY, NOW() - INTERVAL 5 DAY
FROM orders o WHERE o.order_number = 'TM-SAMPLE-0001';

-- ---- Sample order 2: PENDING (awaiting payment) ---------------------
SELECT 'TM-SAMPLE-0002', u.id, 'PENDING', 599980.00, 47998.40, 350.00, 648328.40,
       '45 Peradeniya Road, Kandy', NOW() - INTERVAL 1 DAY
FROM users u WHERE u.username = 'customer';

SELECT o.id, p.id, 2, 299990.00, 599980.00, p.name, p.sku
FROM orders o JOIN products p ON p.sku = 'SM-PIX8P'
WHERE o.order_number = 'TM-SAMPLE-0002';

-- ---- A back-in-stock subscription for the out-of-stock product ------
SELECT u.id, p.id, FALSE, NOW()
FROM users u CROSS JOIN products p
WHERE u.username = 'customer' AND p.sku = 'AC-UGHUB';
